mapper.select:
SELECT COUNT(*)
FROM CHILD_INVITE
WHERE invite_code = #{inviteCode}

SELECT frame_id
FROM FRAME
WHERE frame_type = #{frameType}

mapper.update:
UPDATE CHILD
SET frame_id = (
    SELECT frame_id
    FROM FRAME
    WHERE frame_type = #{frameType}
)
WHERE child_id = #{childId}
  AND EXISTS (
    SELECT 1
    FROM FRAME
    WHERE frame_type = #{frameType}
  )

UPDATE CHILD
SET frame_id = #{frameId}
WHERE child_id = #{childId}
  AND EXISTS (
    SELECT 1
    FROM FRAME
    WHERE frame_id = #{frameId}
  )

UPDATE CHILD_INVITE
SET invite_code = #{inviteCode},
    regenerated_at = SYSTIMESTAMP
WHERE invite_id = (
    SELECT invite_id
    FROM CHILD
    WHERE child_id = #{childId}
      AND parent_id = #{parentId}
)
